## 3. The pybind11 binding (`binding.cpp`)

```cpp
// ---------------------------------------------------------------
// binding.cpp  – pybind11 wrapper for libpcapng
// ---------------------------------------------------------------
#include <pybind11/pybind11.h>
#include <pybind11/stl.h>          // automatic conversion of std::vector, std::string …
#include <pybind11/functional.h>   // for py::function
#include <pybind11/bytes.h>        // for py::bytes
#include "pcapng.hpp"              // <-- replace with the real header

namespace py = pybind11;
using namespace libpcapng;

// -------------------------------------------------------------------
// Helper: convert a Frame to a Python dict (read‑only view)
// -------------------------------------------------------------------
static py::dict frame_to_dict(const Frame& f) {
    py::dict d;
    d["timestamp_ns"]   = f.timestamp_ns;
    d["captured_len"]   = f.captured_len;
    d["original_len"]   = f.original_len;
    d["data"]           = py::bytes(reinterpret_cast<const char*>(f.data.data()),
                                    f.data.size());
    return d;
}

// -------------------------------------------------------------------
// A thin wrapper that makes the C++ iterator look like a Python iterator
// -------------------------------------------------------------------
class FrameIterator {
public:
    explicit FrameIterator(PcapngFile::iterator it,
                           PcapngFile::iterator end)
        : it_(it), end_(end) {}

    // Python's iterator protocol -------------------------------------------------
    FrameIterator& iter() { return *this; }

    py::object next() {
        if (it_ == end_)
            throw py::stop_iteration();

        // Make a *copy* of the Frame so that the underlying C++ container can be
        // destroyed without dangling references.
        Frame f = *it_;
        ++it_;
        // Return a dict – you could also expose a dedicated `Frame` class
        // if you need richer semantics.
        return py::cast(frame_to_dict(f));
    }

private:
    PcapngFile::iterator it_;
    PcapngFile::iterator end_;
};

// -------------------------------------------------------------------
// The public class that Python code will instantiate
// -------------------------------------------------------------------
class PcapngReader {
public:
    explicit PcapngReader(const std::string& filename)
        : file_(filename) {}

    // ----------------------------------------------------------------
    //   Python iterator protocol – `for frame in reader: …`
    // ----------------------------------------------------------------
    FrameIterator iter() const {
        return FrameIterator(file_.begin(), file_.end());
    }

    // ----------------------------------------------------------------
    //   Convenience method that accepts a Python callable and invokes it
    //   for every frame.  This is the API you asked for.
    // ----------------------------------------------------------------
    void for_each(py::function callback) const {
        // Acquire the GIL once per iteration.  The GIL is released while we
        // walk the C++ iterator (which is cheap) to avoid holding it unnecessarily.
        for (auto it = file_.begin(); it != file_.end(); ++it) {
            py::gil_scoped_acquire acquire;   // ensure we have the GIL
            callback(frame_to_dict(*it));
        }
    }

    // ----------------------------------------------------------------
    //   Optional: expose the total number of frames (useful for progress bars)
    // ----------------------------------------------------------------
    std::size_t size() const {
        return std::distance(file_.begin(), file_.end());
    }

private:
    PcapngFile file_;
};

// -------------------------------------------------------------------
//   pybind11 module definition
// -------------------------------------------------------------------
PYBIND11_MODULE(pcapng_binding, m) {
    m.doc() = "Python bindings for libpcapng – iterator + callback API";

    // ----------------------------------------------------------------
    //  Expose the Frame as a dict‑like object (optional – you can also expose
    //  a full class if you need methods on it).
    // ----------------------------------------------------------------
    py::class_<Frame>(m, "Frame")
        .def_property_readonly("timestamp_ns",   [](const Frame& f){ return f.timestamp_ns; })
        .def_property_readonly("captured_len",   [](const Frame& f){ return f.captured_len; })
        .def_property_readonly("original_len",   [](const Frame& f){ return f.original_len; })
        .def_property_readonly("data",           [](const Frame& f){
                return py::bytes(reinterpret_cast<const char*>(f.data.data()), f.data.size());
            })
        .def("__repr__", [](const Frame& f) {
                return "<Frame ts=" + std::to_string(f.timestamp_ns) +
                       " len=" + std::to_string(f.captured_len) + ">";
            });

    // ----------------------------------------------------------------
    //  Expose the iterator wrapper (private – we expose it only via the
    //  reader's __iter__ protocol).
    // ----------------------------------------------------------------
    py::class_<FrameIterator>(m, "_FrameIterator")
        .def("__iter__", &FrameIterator::iter, py::keep_alive<0, 1>()) // keep reader alive
        .def("__next__", &FrameIterator::next);

    // ----------------------------------------------------------------
    //  The user‑facing class
    // ----------------------------------------------------------------
    py::class_<PcapngReader>(m, "PcapngReader")
        .def(py::init<const std::string&>(),
             py::arg("filename"),
             "Open a PCAP‑NG file for reading.")
        .def("__iter__", &PcapngReader::iter, py::keep_alive<0, 1>(),
             "Iterate over frames – yields a dict per frame.")
        .def("for_each", &PcapngReader::for_each,
             py::arg("callback"),
             "Call *callback(frame_dict)* for each frame in the file.\n"
             "The callback is executed with the GIL held; any Python exception will stop iteration.")
        .def("size", &PcapngReader::size,
             "Number of frames in the file.")
        .def("__repr__", [](const PcapngReader& r){
                return "<PcapngReader size=" + std::to_string(r.size()) + ">";
            });
}
```

### What the binding does

| Python API | C++ implementation | Remarks |
|------------|-------------------|---------|
| `reader = PcapngReader("capture.pcapng")` | `PcapngReader(const std::string&)` | Opens the file (or in the mock generates synthetic frames). |
| `for frame in reader:` | `PcapngReader::iter()` → `FrameIterator` → `__next__` | The iterator yields a **Python `dict`** with keys `timestamp_ns`, `captured_len`, `original_len`, `data`.  You could replace the dict with a full‑blown `Frame` class if you need methods. |
| `reader.for_each(callback)` | `PcapngReader::for_each(py::function)` | Walks the C++ iterator and calls the supplied Python callable for each frame. The GIL is acquired for each call, and any exception propagates out of `for_each`. |
| `len(reader)` (optional) | `PcapngReader::size()` | Returns frame count – handy for progress bars.  If you want `len(reader)`, add `def("__len__", &PcapngReader::size)`. |

