## 4. CMake build script (`CMakeLists.txt`)

```cmake
cmake_minimum_required(VERSION 3.14)
project(pcapng_binding LANGUAGES CXX)

# ---------------------------------------------------------
# 1. Find pybind11 – you can also use the single‑header version
# ---------------------------------------------------------
find_package(pybind11 REQUIRED)

# ---------------------------------------------------------
# 2. Create the Python extension module
# ---------------------------------------------------------
add_library(pcapng_binding MODULE binding.cpp)   # <-- our source file
target_include_directories(pcapng_binding PRIVATE ${CMAKE_CURRENT_SOURCE_DIR}) # for pcapng.hpp

# C++17 (or later) is required for libpcapng anyway
target_compile_features(pcapng_binding PRIVATE cxx_std_17)

# Link pybind11
target_link_libraries(pcapng_binding PRIVATE pybind11::module)

# ---------------------------------------------------------
# 3. Platform‑specific tweaks (Linux/macOS/Windows)
# ---------------------------------------------------------
set_target_properties(pcapng_binding PROPERTIES
    PREFIX ""                     # remove the leading "lib" on Linux/macOS
    OUTPUT_NAME pcapng_binding    # the name that Python will import
    SUFFIX "${PYTHON_MODULE_EXTENSION}"
)
```

### Build instructions

```bash
# 1️⃣  Install pybind11 (e.g. via pip or your system package manager)
#     pip install pybind11   # gives you the headers + a CMake config file

# 2️⃣  Create a build directory
mkdir build && cd build
cmake .. -DPython3_EXECUTABLE=$(which python3)   # optional: point to your interpreter
cmake --build . --config Release
```

The result is a shared library `pcapng_binding.*so` (Linux/macOS) or `pcapng_binding.*pyd` (Windows) placed in the build directory.  Copy or symlink it next to `test.py` (or install it with `pip install .` if you wrap it in a proper package).

