## 5. Example Python usage (`test.py`)

```python
#!/usr/bin/env python3
# ---------------------------------------------------------------
# test.py – demo of the binding
# ---------------------------------------------------------------
import sys
import time
from pcapng_binding import PcapngReader

def my_callback(frame):
    """
    This function will be called for every frame.
    `frame` is a dict with the following keys:
        - timestamp_ns : int
        - captured_len : int
        - original_len : int
        - data         : bytes
    """
    # Example: print the first 8 bytes as hex and the timestamp
    ts_sec = frame["timestamp_ns"] // 1_000_000_000
    ts_nan = frame["timestamp_ns"] % 1_000_000_000
    print(f"[{ts_sec}.{ts_nan:09d}] len={frame['captured_len']} data={frame['data'][:8].hex()}…")

def main(pcap_file):
    reader = PcapngReader(pcap_file)
    print(f"Opened {pcap_file!r}, contains {reader.size()} frames.\n")

    # -----------------------------------------------------------------
    # 1) Using the Python iterator (most Pythonic)
    # -----------------------------------------------------------------
    print("Iterating with a for‑loop:")
    for frame in reader:
        my_callback(frame)

    # -----------------------------------------------------------------
    # 2) Using the explicit `for_each` helper (exactly what you asked for)
    # -----------------------------------------------------------------
    print("\nRunning the same callback via for_each():")
    start = time.perf_counter()
    reader.for_each(my_callback)
    elapsed = time.perf_counter() - start
    print(f"\nProcessed {reader.size()} frames in {elapsed:.3f} s")

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print(f"Usage: {sys.argv[0]} <pcapng-file>")
        sys.exit(1)
    main(sys.argv[1])
```

